class Solution {
    public long smallestNumber(long num) {
        if (num < 0) {
            String str = String.valueOf(-num);
            char[] chars = str.toCharArray();
            Arrays.sort(chars);
            int index = 0;
            while (index < chars.length && chars[index] == '0') {
                index++;
            }
            if (index == chars.length) {
                return -Long.parseLong(new String(chars));
            }
            char temp = chars[0];
            chars[0] = chars[index];
            chars[index] = temp;
            return -Long.parseLong(new String(chars));
        } else {
            String str = String.valueOf(num);
            char[] chars = str.toCharArray();
            Arrays.sort(chars);
            return Long.parseLong(new String(chars));
        }
    }
}
